INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '0acc0f65-837b-4755-8e16-19237bac793c',
  '00000000-0000-0000-0000-000000000001',
  $escape$esp32: Microcontroller vs Microprocessor - Bare Metal vs RTOS$escape$,
  $escape$The esp32 contains a dual-core Xtensa LX6 microprocessor. However, when working at the hardware level, you interact with the microcontroller, which includes the CPU, peripherals, and memory. Bare-metal programming means writing code that directly interacts with hardware registers. This is useful for low-level tasks like interrupt handling and peripheral configuration. On the other hand, using a Real-Time Operating System (RTOS) like FreeRTOS provides a higher-level abstraction, allowing you to focus on application logic while the RTOS handles tasks scheduling and synchronization.$escape$,
  $escape$['#include <driver/gpio.h>', 'void setup() {', '    gpio_pad_select_gpio(GPIO_NUM_2);', '    gpio_set_direction(GPIO_NUM_2, GPIO_MODE_OUTPUT);', '}', 'void loop() {', '    gpio_set_level(GPIO_NUM_2, HIGH);', '    delay(1000);', '    gpio_set_level(GPIO_NUM_2, LOW);', '    delay(1000);', '}']$escape$,
  $escape$c$escape$,
