INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'f16ccc8f-d599-4ccd-819b-1ffe7be6c3f0',
  '00000000-0000-0000-0000-000000000001',
  $escape$esp32 Power Management: Maximizing Battery Life with Sleep Modes$escape$,
  $escape$The esp32's power management system is designed to minimize power consumption. The `esp_sleep()` function is used to enter deep sleep modes, including `ESP_SLEEP_MODE_NONE`, `ESP_SLEEP_MODE_LIGHT`, `ESP_SLEEP_MODE_DEEP`, and `ESP_SLEEP_MODE_ULP`. To wake from deep sleep, use `esp_add_wake_source()` with a `WAKE_SOURCE_TOUCH` or `WAKE_SOURCE_EXT0` for touch or external pin wake, respectively. For example, to wake from deep sleep on touch, set `WAKE_SOURCE_TOUCH` and call `esp_sleep_enable_touch_wakeup()`. To optimize battery life, use `esp_deep_sleep()`, which disables peripherals, and set `ESP_SLEEP_MODE_DEEP` and `WAKE_SOURCE_TOUCH`.$escape$,
  $escape$esp_err_t wakeSource = esp_add_wake_source(BIT2, 0, ESP_INTR_FLAG_DEFAULT);
if (wakeSource == ESP_OK) {
    esp_sleep_enable_touch_wakeup();
    esp_deep_sleep();
}$escape$,
  $escape$c$escape$,
