INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '72ac103a-a934-4843-81d9-66b72a441873',
  '00000000-0000-0000-0000-000000000001',
  $escape$esp32 - Choosing the Right I2C Protocol for Your Sensor$escape$,
  $escape$When communicating with I2C sensors on the esp32, you'll often encounter the choice between standard (100 kHz) and fast (400 kHz) modes. The esp32's I2C peripheral supports both modes, but the decision depends on your sensor's requirements. For example, the popular BME280 temperature and humidity sensor operates at 100 kHz, while the MLX90614 infrared thermometer requires the faster 400 kHz mode. To switch modes, use the `i2c_set_clock_divider` function. Set the divider to 10 for standard mode (100 kHz) or 2 for fast mode (400 kHz). Ensure the sensor's clock speed matches the mode you select to avoid data corruption.$escape$,
  $escape$const i2c = require('esp32-i2c');
const i2cMaster = i2c.begin(0, i2c.SCL_PIN, i2c.SDA_PIN);
i2cMaster.setClockDivider(10); // 100 kHz mode
$escape$,
  $escape$javascript$escape$,
