INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'e09fc0a8-c678-4f7e-889e-b32b46e60794',
  '00000000-0000-0000-0000-000000000001',
  $escape$ESP32 Dev: Arduino vs ESP32 vs Raspberry Pi vs STM32 — Decision Framework$escape$,
  $escape$When choosing a platform for your ESP32 project, consider the following factors: 1) Complexity: If you're new to ESP32, the Arduino IDE provides an easier learning curve. 2) Resource requirements: ESP32 has a smaller footprint compared to Raspberry Pi. 3) Performance: For demanding tasks, consider STM32. 4) Development time: Use ESP32 if you need rapid prototyping. 5) Libraries and community: ESP32 has extensive libraries and a large community.$escape$,
  NULL,
  NULL,
